import React, { useState, useEffect } from 'react';
import ProductService from './ProductService';
import { getAllUsers, deleteUser, approveSupplierRequest } from './UserService';
import { collection, getDocs, doc, deleteDoc } from 'firebase/firestore';  // Import the required functions
import { db } from './firebase';
import './AdminDashboard.css';

const AdminDashboard = () => {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [pricePerDay, setPricePerDay] = useState('');
  const [mainImageFile, setMainImageFile] = useState(null);
  const [additionalImageFiles, setAdditionalImageFiles] = useState([]);
  const [category, setCategory] = useState('Clothing');
  const [subcategory, setSubcategory] = useState('Men');
  const [users, setUsers] = useState([]);
  const [supplierRequests, setSupplierRequests] = useState([]);

  useEffect(() => {
    fetchUsers();
    fetchSupplierRequests();
  }, []);

  const fetchUsers = async () => {
    try {
      const usersList = await getAllUsers();
      setUsers(usersList);
    } catch (error) {
      console.error('Error fetching users:', error);
    }
  };

  const fetchSupplierRequests = async () => {
    try {
      const requestsCollection = collection(db, 'supplierRequests');
      const querySnapshot = await getDocs(requestsCollection);
      console.log('Query Snapshot:', querySnapshot);

      const requests = querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      console.log('Fetched Requests:', requests);

      setSupplierRequests(requests);
    } catch (error) {
      console.error('Error fetching supplier requests:', error);
    }
  };

  const handleAdditionalImagesChange = (e) => {
    setAdditionalImageFiles(e.target.files);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const newProduct = {
      name,
      description,
      pricePerDay: parseInt(pricePerDay, 10),
      category,
      subcategory
    };

    try {
      await ProductService.addProduct(newProduct, mainImageFile, additionalImageFiles);
      setName('');
      setDescription('');
      setPricePerDay('');
      setMainImageFile(null);
      setAdditionalImageFiles([]);
    } catch (error) {
      console.error("Error adding product:", error);
    }
  };

  const handleDeleteUser = async (userId) => {
    try {
      await deleteUser(userId);
      setUsers(users.filter(user => user.id !== userId));
    } catch (error) {
      console.error('Error deleting user:', error);
    }
  };

  const handleApproveSupplier = async (requestId) => {
    try {
      await approveSupplierRequest(requestId);
      setSupplierRequests(supplierRequests.filter(request => request.id !== requestId));
    } catch (error) {
      console.error('Error approving supplier request:', error);
    }
  };

  const handleDenySupplier = async (requestId) => {
    try {
      await deleteDoc(doc(db, 'supplierRequests', requestId));
      setSupplierRequests(supplierRequests.filter(request => request.id !== requestId));
    } catch (error) {
      console.error('Error denying supplier request:', error);
    }
  };

  return (
    <div className="admin-dashboard">
      <div className="form-container">
        <form onSubmit={handleSubmit} className="add-product-form">
          <label>
            Name:
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
            />
          </label>
          <label>
            Description:
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              required
            />
          </label>
          <label>
            Price per Day:
            <input
              type="number"
              value={pricePerDay}
              onChange={(e) => setPricePerDay(e.target.value)}
              required
            />
          </label>
          <label>
            Main Image:
            <input
              type="file"
              accept="image/*"
              onChange={(e) => setMainImageFile(e.target.files[0])}
              required
            />
          </label>
          <label>
            Additional Images:
            <input
              type="file"
              accept="image/*"
              multiple
              onChange={handleAdditionalImagesChange}
            />
            {additionalImageFiles.length > 0 && (
              <div className="image-preview">
                {Array.from(additionalImageFiles).map((file, index) => (
                  <img key={index} src={URL.createObjectURL(file)} alt={`Additional ${index + 1}`} />
                ))}
              </div>
            )}
          </label>
          <label>
            Category:
            <select
              value={category}
              onChange={(e) => setCategory(e.target.value)}
            >
              <option value="Clothing">Clothing</option>
              <option value="Footwear">Footwear</option>
              <option value="Gear">Gear</option>
              <option value="Accessories">Accessories</option>
            </select>
          </label>
          <label>
            Subcategory:
            <select
              value={subcategory}
              onChange={(e) => setSubcategory(e.target.value)}
            >
              {category === 'Clothing' && (
                <>
                  <option value="Men">Men's Clothing</option>
                  <option value="Women">Women's Clothing</option>
                  <option value="Kids">Kids' Clothing</option>
                </>
              )}
              {category === 'Footwear' && (
                <>
                  <option value="Men">Men's Footwear</option>
                  <option value="Women">Women's Footwear</option>
                  <option value="Kids">Kids' Footwear</option>
                </>
              )}
              {category === 'Gear' && (
                <>
                  <option value="Kitchen">Camp Kitchen</option>
                  <option value="Packs">Packs</option>
                  <option value="Sleep">Sleep Systems</option>
                  <option value="Tents">Tents & Bivvies</option>
                  <option value="Additional">Additional Gear</option>
                </>
              )}
              {category === 'Accessories' && (
                <>
                  <option value="Headwear">Headwear</option>
                  <option value="Clothing">Clothing Accessories</option>
                  <option value="Footwear">Footwear Accessories</option>
                  <option value="Backpack">Backpack Accessories</option>
                </>
              )}
            </select>
          </label>
          <button type="submit">Add Product</button>
        </form>
      </div>
      <div className="user-list">
        <h2>All Users</h2>
        <ul>
          {users.map(user => (
            <li key={user.id}>
              {user.name} ({user.email}) 
              <button onClick={() => handleDeleteUser(user.id)}>Delete</button>
            </li>
          ))}
        </ul>
      </div>
      <div className="supplier-requests">
        <h2>Supplier Requests</h2>
        <ul>
          {supplierRequests.length > 0 ? (
            supplierRequests.map(request => (
              <li key={request.id}>
                {request.userName} ({request.userEmail})
                <button onClick={() => handleApproveSupplier(request.id)}>Approve</button>
                <button onClick={() => handleDenySupplier(request.id)}>Deny</button>
              </li>
            ))
          ) : (
            <p>No supplier requests found.</p>
          )}
        </ul>
      </div>
    </div>
  );
};

export default AdminDashboard;
